35	@ApplicationScoped
36	public class SnsService {
37	
38	    private static final Logger LOG = Logger.getLogger(SnsService.class);
39	    private static final Duration FIFO_DEDUP_WINDOW = Duration.ofMinutes(5);
40	    private static final List<String> PENDING_CONFIRMATION_PROTOCOLS =
41	            List.of("http", "https", "email", "email-json", "sms");
42	
43	    private final StorageBackend<String, Topic> topicStore;
44	    private final StorageBackend<String, Subscription> subscriptionStore;
45	    private final RegionResolver regionResolver;
46	    private final SqsService sqsService;
47	    private final LambdaService lambdaService;
48	    private final String baseUrl;
49	    private final ObjectMapper objectMapper;
50	    private final Map<String, Instant> fifoDeduplicationCache = new ConcurrentHashMap<>();
51	
52	    @Inject
53	    public SnsService(StorageFactory storageFactory, EmulatorConfig config,
54	                      RegionResolver regionResolver, SqsService sqsService,
55	                      LambdaService lambdaService, ObjectMapper objectMapper) {
56	        this(
57	                storageFactory.create("sns", "sns-topics.json",
58	                        new TypeReference<Map<String, Topic>>() {
59	                        }),
60	                storageFactory.create("sns", "sns-subscriptions.json",
61	                        new TypeReference<Map<String, Subscription>>() {
62	                        }),
63	                regionResolver,
64	                sqsService,
65	                lambdaService,
66	                config.effectiveBaseUrl(),
67	                objectMapper
68	        );
69	    }
70	
71	    /**
72	     * Package-private constructor for testing.
73	     */
74	    SnsService(StorageBackend<String, Topic> topicStore,
75	               StorageBackend<String, Subscription> subscriptionStore,
76	               RegionResolver regionResolver, SqsService sqsService,
77	               LambdaService lambdaService) {
78	        this(topicStore, subscriptionStore, regionResolver, sqsService, lambdaService, "http://localhost:4566",
79	                new ObjectMapper());
80	    }
81	
82	    SnsService(StorageBackend<String, Topic> topicStore,
83	               StorageBackend<String, Subscription> subscriptionStore,
84	               RegionResolver regionResolver, SqsService sqsService,
85	               LambdaService lambdaService, String baseUrl, ObjectMapper objectMapper) {
86	        this.topicStore = topicStore;
87	        this.subscriptionStore = subscriptionStore;
88	        this.regionResolver = regionResolver;
89	        this.sqsService = sqsService;
90	        this.lambdaService = lambdaService;
91	        this.baseUrl = baseUrl;
92	        this.objectMapper = objectMapper;
